local function keys(d3)
    local v={}
    for ej in pairs(d3) do
        table.insert(v,ej)
    end
    return v
end
local function values(d3)
    local v={}
    for ev,d3 in pairs(d3) do
        table.insert(v,d3)
    end
    return v
end
local function entries(d3)
    local v={}
    for ej,d3 in pairs(d3) do
        table.insert(v,{ej,d3})
    end
    return v
end
local function clone(d3)
    local v={}
    for ej,d3 in pairs(d3) do
        v[ej]=d3
    end
    return v
end
local function merge(...)
    local v={}
    for c2=1,select("#",...) do
        local q_=select(c2,...)
        if q_~=nil then
            for ej,d3 in pairs(q_) do
                v[ej]=d3
            end
        end
    end
    return v
end
local function deepClone(d3)
    local v={}
    for ej,d3 in pairs(d3) do
        if type(d3)=="table" then
            v[ej]=deepClone(d3)
        else
            v[ej]=d3
        end
    end
    return v
end
